#ifndef ESEC_SM4_BASICS_HEADER
#define ESEC_SM4_BASICS_HEADER

#include <stdint.h>
#include <stddef.h>

#include "esec_errors.h"
#include "esec_symm_basics.h"

/** Size of the IV for SM4 */
#define ESEC_SM4_IV_SIZE 16

/** Size of the IV for SM4 - GCM */
#define ESEC_SM4_GCM_IV_SIZE 12

/* Block size for SM4 algorithms. */
#define ESEC_SM4_BLOCK_SIZE 16

/* Key size for SM4 algorithms. */
#define ESEC_SM4_KEY_SIZE 16

/** Size of the authentication tag generated by the SM4 GCM algorithm */
#define ESEC_TAG_SIZE_SM4_GCM 16

enum esec_sm4_mode {
    ESEC_SM4_ECB = 0x01,
    ESEC_SM4_CBC = 0x02,
    ESEC_SM4_CTR = 0x03,
    ESEC_SM4_CFB = 0x04,
    ESEC_SM4_OFB = 0x05,
};

#endif
